def count_characters():
    fh = open('story.txt', 'r')
    data = fh.read()
    vowels = consonants = upper = lower = 0
    for ch in data:
        if ch.isalpha():
            if ch.lower() in 'aeiou':
                vowels += 1
            else:
                consonants += 1
            if ch.isupper():
                upper += 1
            else:
                lower += 1
    fh.close()
    print('Vowels:', vowels)
    print('Consonants:', consonants)
    print('Uppercase:', upper)
    print('Lowercase:', lower)

count_characters()

def count_types():
    fh = open('data.txt', 'r')
    data = fh.read()
    digits = spaces = special = 0
    for ch in data:
        if ch.isdigit():
            digits += 1
        elif ch.isspace():
            spaces += 1
        elif not ch.isalpha():
            special += 1
    fh.close()
    print('Digits:', digits)
    print('Spaces:', spaces)
    print('Special characters:', special)

count_types()

