import pickle

def update_record(roll_no, new_marks):
    fh = open('students.dat', 'rb')
    records = []
    try:
        while True:
            record = pickle.load(fh)
            records.append(record)
    except EOFError:
        fh.close()

    found = False
    for record in records:
        if record[0] == roll_no:
            record[2] = new_marks
            found = True

    if found:
        fh = open('students.dat', 'wb')
        for record in records:
            pickle.dump(record, fh)
        fh.close()
        print('Record updated successfully')
    else:
        print('Record not found')

update_record(2, 95.0)

stack = []

def push(item):
    stack.append(item)
    print(item, 'pushed to stack')

def pop():
    if stack == []:
        print('Stack Underflow!')
    else:
        item = stack.pop()
        print(item, 'popped from stack')

def display():
    if stack == []:
        print('Stack is empty')
    else:
        print('Stack (top to bottom):')
        for i in range(len(stack) - 1, -1, -1):
            print(stack[i])

push(10)
push(20)
push(30)
display()
pop()
display()

