stack = [10, 20, 30, 40, 50]

def peek():
    if stack == []:
        print('Stack is empty')
    else:
        print('Top element:', stack[-1])

def display():
    if stack == []:
        print('Stack is empty')
    else:
        top = len(stack) - 1
        print('Stack contents:')
        for i in range(top, -1, -1):
            if i == top:
                print(stack[i], '<-- TOP')
            else:
                print(stack[i])

peek()
display()

def factorial(n):
    if n == 0 or n == 1:
        return 1
    else:
        return n * factorial(n - 1)

num = 5
result = factorial(num)
print('Factorial of', num, '=', result)

def sum_of_digits(n):
    if n == 0:
        return 0
    else:
        return n % 10 + sum_of_digits(n // 10)

num = 1234
result = sum_of_digits(num)
print('Sum of digits of', num, '=', result)

def fibonacci(n):
    if n == 1:
        return 0
    elif n == 2:
        return 1
    else:
        return fibonacci(n - 1) + fibonacci(n - 2)

for i in range(1, 8):
    print(fibonacci(i), end=' ')
print()

def power(x, n):
    if n == 0:
        return 1
    else:
        return x * power(x, n - 1)

base = 2
exp = 5
result = power(base, exp)
print(base, 'raised to', exp, '=', result)

-- Display employees with salary between 30000 and 60000
SELECT * FROM EMPLOYEE WHERE Salary BETWEEN 30000 AND 60000;

-- Display employees from Delhi or Mumbai
SELECT Name, City FROM EMPLOYEE WHERE City IN ('Delhi', 'Mumbai');

-- Display employees whose name starts with 'A'
SELECT * FROM EMPLOYEE WHERE Name LIKE 'A%';

-- Display employees whose name has exactly 4 characters
SELECT * FROM EMPLOYEE WHERE Name LIKE '____';

-- Display employees whose name contains 'an' anywhere
SELECT * FROM EMPLOYEE WHERE Name LIKE '%an%';

-- Sort employees by name in ascending order (default)
SELECT * FROM EMPLOYEE ORDER BY Name;

-- Sort employees by salary in descending order
SELECT * FROM EMPLOYEE ORDER BY Salary DESC;

-- Sort by department ascending, then by salary descending
SELECT Name, Department, Salary
FROM EMPLOYEE
ORDER BY Department ASC, Salary DESC;

-- Display top 3 highest paid employees
SELECT * FROM EMPLOYEE ORDER BY Salary DESC LIMIT 3;

-- Total number of employees
SELECT COUNT(*) AS TotalEmployees FROM EMPLOYEE;

-- Total salary expenditure
SELECT SUM(Salary) AS TotalSalary FROM EMPLOYEE;

-- Average salary
SELECT AVG(Salary) AS AvgSalary FROM EMPLOYEE;

-- Highest and lowest salary
SELECT MAX(Salary) AS Highest, MIN(Salary) AS Lowest FROM EMPLOYEE;

-- Count of distinct departments
SELECT COUNT(DISTINCT Department) AS Departments FROM EMPLOYEE;

-- Max salary in each department
SELECT Department, MAX(Salary) AS MaxSalary
FROM EMPLOYEE
GROUP BY Department;

-- Increase salary by 10% for all employees in 'Sales' department
UPDATE EMPLOYEE SET Salary = Salary * 1.10
WHERE Department = 'Sales';

-- Change department of employee with EmpNo 103
UPDATE EMPLOYEE SET Department = 'HR'
WHERE EmpNo = 103;

-- Delete employees with salary less than 20000
DELETE FROM EMPLOYEE WHERE Salary < 20000;

-- Delete all records (but keep table structure)
